USE advance_care_hospital;

CREATE TABLE IF NOT EXISTS pages(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,slug VARCHAR(100) UNIQUE NOT NULL,title VARCHAR(180) NOT NULL,subtitle VARCHAR(255),body LONGTEXT NOT NULL,image VARCHAR(255),is_published BOOLEAN DEFAULT TRUE,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS leaders(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,designation VARCHAR(150) NOT NULL,category ENUM('chairman','managing_director','board','administration') NOT NULL,qualifications VARCHAR(255),message LONGTEXT,photo VARCHAR(255),display_order INT DEFAULT 0,is_active BOOLEAN DEFAULT TRUE)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS departments(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) UNIQUE NOT NULL,slug VARCHAR(140) UNIQUE NOT NULL,icon VARCHAR(50),short_description VARCHAR(300),description LONGTEXT,services TEXT,facilities TEXT,image VARCHAR(255),is_featured BOOLEAN DEFAULT FALSE,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS doctors(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,slug VARCHAR(140) UNIQUE NOT NULL,designation VARCHAR(150),specialization VARCHAR(150) NOT NULL,qualifications VARCHAR(255),experience_years INT UNSIGNED DEFAULT 0,consultation_fee DECIMAL(10,2) DEFAULT 0,bio TEXT,photo VARCHAR(255),available_days VARCHAR(150),available_time VARCHAR(100),is_featured BOOLEAN DEFAULT FALSE,is_active BOOLEAN DEFAULT TRUE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS doctor_departments(doctor_id BIGINT UNSIGNED NOT NULL,department_id BIGINT UNSIGNED NOT NULL,PRIMARY KEY(doctor_id,department_id),FOREIGN KEY(doctor_id)REFERENCES doctors(id)ON DELETE CASCADE,FOREIGN KEY(department_id)REFERENCES departments(id)ON DELETE CASCADE)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS diagnostic_categories(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) UNIQUE NOT NULL,is_active BOOLEAN DEFAULT TRUE)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS diagnostic_tests(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,category_id BIGINT UNSIGNED NOT NULL,name VARCHAR(160) UNIQUE NOT NULL,description TEXT,preparation TEXT,price DECIMAL(10,2) DEFAULT 0,report_time VARCHAR(100),is_active BOOLEAN DEFAULT TRUE,FOREIGN KEY(category_id)REFERENCES diagnostic_categories(id))ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS facilities(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(140) UNIQUE NOT NULL,slug VARCHAR(150) UNIQUE NOT NULL,icon VARCHAR(50),short_description VARCHAR(300),description TEXT,image VARCHAR(255),availability VARCHAR(100),contact VARCHAR(30),is_featured BOOLEAN DEFAULT FALSE,is_active BOOLEAN DEFAULT TRUE)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS cabin_types(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) UNIQUE NOT NULL,description TEXT,daily_charge DECIMAL(10,2) NOT NULL,capacity INT UNSIGNED DEFAULT 1,amenities TEXT,image VARCHAR(255),availability ENUM('available','limited','unavailable') DEFAULT 'available',is_active BOOLEAN DEFAULT TRUE)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS news(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,title VARCHAR(180) NOT NULL,slug VARCHAR(200) UNIQUE NOT NULL,category VARCHAR(100),excerpt VARCHAR(350),body LONGTEXT,image VARCHAR(255),published_at DATETIME,author VARCHAR(120),is_published BOOLEAN DEFAULT TRUE,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS patient_video_reviews(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,title VARCHAR(180) NOT NULL,patient_name VARCHAR(120) DEFAULT 'Verified Patient',department_id BIGINT UNSIGNED NULL,platform ENUM('youtube','facebook') NOT NULL,video_url VARCHAR(500) NOT NULL,embed_url VARCHAR(500) NOT NULL,thumbnail VARCHAR(500),description TEXT,consent_recorded BOOLEAN DEFAULT FALSE,is_featured BOOLEAN DEFAULT FALSE,is_published BOOLEAN DEFAULT FALSE,published_at DATETIME,FOREIGN KEY(department_id)REFERENCES departments(id)ON DELETE SET NULL)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS contact_messages(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(190),phone VARCHAR(20) NOT NULL,subject VARCHAR(180) NOT NULL,message TEXT NOT NULL,status ENUM('new','read','resolved') DEFAULT 'new',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)ENGINE=InnoDB;
CREATE TABLE IF NOT EXISTS feedback(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120),phone VARCHAR(20),service VARCHAR(120),rating TINYINT UNSIGNED NOT NULL,comments TEXT NOT NULL,is_anonymous BOOLEAN DEFAULT FALSE,status ENUM('pending','published','archived') DEFAULT 'pending',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CHECK(rating BETWEEN 1 AND 5))ENGINE=InnoDB;

