INSERT IGNORE INTO pages(slug,title,subtitle,body)VALUES
('about','About Advance Care Specialized Hospital','Compassionate healthcare supported by modern technology.','Advance Care Specialized Hospital is committed to accessible, ethical and patient-centred healthcare. Our multidisciplinary teams work together to provide safe and coordinated services.\n\nMission: Deliver dependable specialist care with compassion and integrity.\n\nVision: Become a trusted digital-first healthcare institution in Bangladesh.\n\nCore values: Compassion, integrity, excellence, safety, innovation and accessibility.'),
('administration','Hospital Administration','Leadership focused on quality, safety and service.','Our administration coordinates clinical services, nursing, operations, patient support and continuous quality improvement.');
